//-------------------------------------------------
// 자식창에서 CY 상태값 받아서 처리하는 함수
// returnVal - 0: 혼잡하지 않음, 1: 혼잡, 2: 고장
// vTime     - xx분, 미정, null
//-------------------------------------------------
scwin.f_displayCongestion = function (returnVal, vTime) {
  //혼잡도 예정종료시간이 지났지만 혼잡상태가 자동업데이트 되지 않은경우 - 임시처리
  /*
  if(cfIsNull(vTime.trim())){
      returnVal = 0;
  }else{
  //대기시간이 -가 되는경우 예외처리
  if(vTime.substr(0,1)=="-"){
      returnVal = 0;
  }
  isNaN(숫자) ==> false
  }*/
  var wait = '';
  if (vTime != '미정' || vTime != null) {
    if (vTime.length == 2) {
      wait = vTime.substring(0, 1);
    } else if (vTime.length == 3) {
      wait = vTime.substring(0, 2);
    }
    Number(wait);
  }
  if (returnVal == 0) {
    //혼잡이 아닌경우

    btn_busy.removeClass("btn-green");
    btn_err.removeClass("btn-green");
  } else if (returnVal == 1) {
    //혼잡인 경우
    btn_busy.addClass("btn-green");
    btn_err.removeClass("btn-green");
    if (wait <= 5 && checkAlert == '0') {
      $c.win.alert($p, "CY혼잡 종료 까지 남은시간 : " + wait + "분");
      scwin.checkAlert = '1';
    }
  } else if (returnVal == 2) {
    //고장인경우 ds_outSts
    btn_busy.removeClass("btn-green");
    btn_err.addClass("btn-green");
    if (wait <= 5 && checkAlert == '0') {
      $c.win.alert($p, "장비 수리 종료 까지 남은시간 : " + wait + "분");
      scwin.checkAlert = '1';
    }
  }
  ds_outSts.setCellData(0, "conSts", returnVal);
  //f_resetScanData();
};

