scwin.f_retrieveVehclNo = async function () {
  if (ed_searchVehclNo.getValue() == "") {
    let opt = {};
    let data = {};
    opt.width = "362";
    opt.height = "492";
    opt.id = "popUpAutoCreation";
    opt.title = "";
    opt.popupName = "";
    opt.type = "browserPopup";

    //실제호출
    vReturn = await $c.win.openPopup($p, "/ui/tn/op/transwrkindict/cntr/tn_304_03_02p.xml", opt);

    // var uri = '/tn/op/transwrkindict/cntr/tn_304_03_02p.xml';
    // var popOptions = "dialogWidth: 350px; dialogHeight: 450px; center: yes; resizable: yes; status: no; scroll: no;"; 
    // var vReturn = window.showModalDialog(uri, window,  popOptions );
    if ($c.gus.cfIsNull($p, vReturn) || vReturn == undefined) {
      //document.getElementById("searchVehclNo").value = "";
      ed_searchVehclNo.setValue("");
    } else {
      //document.getElementById("searchVehclNo").value = vReturn;
      ed_searchVehclNo.setValue(vReturn);
    }
  } else {
    ed_searchVehclNo.setValue("");
  }
  scwin.f_retrieve();
};
scwin.retrieve_submitDone = async function () {
  ed_cnt.setValue(ds_outInfo.getRowCount());
  if (ds_outInfo.getRowCount() == 0 && hid_alert_chk.getValue() == 'Y') {
    //cfAlertMsg(MSG_CM_ERR_003);      
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_003);
    hid_alert_chk.setValue("N");
  }
  await scwin.tr_retrieveSts();
};
scwin.tr_retrieveSts = async function () {
  dma_oGDS_view_cond.set("wrkPlCd", scwin.wrkPlCd);
  dma_oGDS_view_cond.set("eqCd", scwin.eqCd);
  await $c.sbm.execute($p, sbm_retrieveSts);
};
scwin.retrieveSts_submitDone = function () {
  if (ds_outSts.getRowCount() == 0) {
    ds_outSts.setCellData(0, "conSts", "0");
  }
  if ($c.gus.cfIsNull($p, ds_outSts.getCellData(0, "conSts"))) {
    ds_outSts.setCellData(0, "conSts", "0");
  }
  if (ds_outSts.getCellData(0, "conSts") == "0") {
    btn_busy.removeClass("btn-green");
    btn_err.removeClass("btn-green");
    // document.getElementById("btn_busy").src = "images/btn_busy.gif" ;
    // document.getElementById("btn_err").src = "images/btn_err.gif" ;
  } else if (ds_outSts.getCellData(0, "conSts") == "1") {
    btn_busy.addClass("btn-green");
    btn_err.removeClass("btn-green");
    // document.getElementById("btn_busy").src = "images/btn_busy_over.gif" 
    // document.getElementById("btn_err").src = "images/btn_err.gif" ;
  } else if (ds_outSts.getCellData(0, "conSts") == "2") {
    btn_busy.removeClass("btn-green");
    btn_err.addClass("btn-green");
    // document.getElementById("btn_busy").src = "images/btn_busy.gif" ;
    // document.getElementById("btn_err").src = "images/btn_err_over.gif" ;
  }
};
